  tip = excluded.tip,
  examples = excluded.examples,
  quiz = excluded.quiz,
  category = excluded.category,
  country_code = excluded.country_code,
  icon = excluded.icon,
  uses = excluded.uses,
  signals = excluded.signals,
  mistakes = excluded.mistakes;
